#ifndef API_KEY_MANAGER_H
#define API_KEY_MANAGER_H

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

typedef struct {
    char key[256];
    char user[128];
    int permissions;
} APIKeyInfo;

static APIKeyInfo key_store[50];

/**
 * @brief Store the API key and associated user information into a secure key table
 * 
 * This function receives an API key string and a user information string, safely copies them into an internal
 * key structure for storage, and computes and returns a hash value of the key for subsequent key lookup and verification.
 *
 * Input/output example:
 *   Input: api_key="sk_live_abc123", user_info="user@example.com"
 *   Output: Returns a non-zero hash value on success; returns 0 if key_store is full or if empty strings are provided
 *
 * @param api_key Null-terminated C string containing the API key
 *                e.g., "sk_live_1234567890abcdef"
 * @param user_info Null-terminated C string containing user identification information
 *                  e.g., "user@example.com" or "UserID:12345"
 * 
 * @return Returns the hash value of the API key as an unsigned long
 *         This hash value can be used for subsequent key retrieval and verification
 *         The return value is a unique identifier computed from the api_key parameter
 */
unsigned long store_api_key(const char* api_key, const char* user_info);

#endif
```

